// Prepare synchronization configuration
const body = $json["body"] || {};

return [{ json: {
  syncDirection: body.syncDirection || 'bidirectional', // bidirectional, export, import
  entityType: body.entityType || 'property', // property, customer, deal, agent
  syncFilters: body.syncFilters || {},
  fieldMappings: body.fieldMappings || {},
  externalSystem: body.externalSystem || 'mls', // mls, accounting, marketing, ERP, etc.
  syncMode: body.syncMode || 'incremental', // full, incremental
  lastSyncToken: body.lastSyncToken || null,
  metadata: body.metadata || {}
} }];

// Perform data synchronization with external system
const { syncDirection, entityType, syncFilters, fieldMappings, externalSystem, syncMode, lastSyncToken, metadata } = $json;

// This would contain actual API calls to external systems
// For demonstration, we'll simulate the sync process

const results = {
  recordsProcessed: 0,
  recordsCreated: 0,
  recordsUpdated: 0,
  recordsFailed: 0,
  recordsSkipped: 0,
  errors: [],
  warnings: []
};

// Simulate processing based on entity type
let recordCount = 0;

switch (entityType) {
  case 'property':
    recordCount = Math.floor(Math.random() * 15) + 5; // 5-20 properties
    break;
  case 'customer':
    recordCount = Math.floor(Math.random() * 10) + 3; // 3-13 customers
    break;
  case 'deal':
    recordCount = Math.floor(Math.random() * 8) + 2; // 2-10 deals
    break;
  case 'agent':
    recordCount = Math.floor(Math.random() * 5) + 1; // 1-6 agents
    break;
  default:
    recordCount = Math.floor(Math.random() * 10) + 2;
}

results.recordsProcessed = recordCount;

// Simulate distribution based on sync direction and mode
if (syncDirection === 'export' || syncDirection === 'bidirectional') {
  // Exporting FROM CRM TO external system
  results.recordsCreated = Math.floor(recordCount * 0.2);
  results.recordsUpdated = Math.floor(recordCount * 0.6);
  results.recordsFailed = Math.floor(recordCount * 0.1);
  results.recordsSkipped = recordCount - (results.recordsCreated + results.recordsUpdated + results.recordsFailed);
}

if (syncDirection === 'import' || syncDirection === 'bidirectional') {
  // Importing FROM external system TO CRM
  results.recordsCreated = Math.floor(recordCount * 0.3);
  results.recordsUpdated = Math.floor(recordCount * 0.5);
  results.recordsFailed = Math.floor(recordCount * 0.1);
  results.recordsSkipped = recordCount - (results.recordsCreated + results.recordsUpdated + results.recordsFailed);
}

// Generate some sample errors/warnings for realism
if (results.recordsFailed > 0) {
  for (let i = 0; i < Math.min(results.recordsFailed, 3); i++) {
    results.errors.push({
      entityId: `${entityType}_${Date.now()}_${i}`,
      error: `Validation failed for ${entityType} field: ${['price', 'email', 'phone'][i] || 'unknown'}`,
      timestamp: new Date().toISOString(),
      severity: 'error'
    });
  }
}

if (Math.random() > 0.7) { // 30% chance of warning
  results.warnings.push({
    type: 'data_quality',
    message: `Some ${entityType} records had missing optional fields`,
    timestamp: new Date().toISOString(),
    severity: 'warning'
  });
}

// Determine overall status
const status = results.recordsFailed === 0 ? 'completed' : 'completed_with_errors';

return [{ json: {
  status,
  syncDirection,
  entityType,
  externalSystem,
  syncMode,
  lastSyncTokenUsed: lastSyncToken,
  results,
  metadata: {
    ...metadata,
    syncedAt: new Date().toISOString(),
    syncFiltersApplied: Object.keys(syncFilters).length > 0 ? syncFilters : {},
    fieldMappingsApplied: Object.keys(fieldMappings).length > 0 ? fieldMappings : {},
    encoding: 'UTF-8'
  }
} }];
